// balanced reports whether every opening bracket is closed by the matching kind
// in the correct order.
func balanced(s string) bool {
	closeToOpen := map[rune]rune{')': '(', ']': '[', '}': '{'}
	var stack []rune
	for _, r := range s {
		switch r {
		case '(', '[', '{':
