		go func(i, id int) {
			defer wg.Done()
			results[i], errs[i] = fetch(id)
		}(i, id)
	}
	wg.Wait()

	for i, id := range ids {
		if errs[i] != nil {
			fmt.Printf("id %d: error: %v\n", id, errs[i])
			continue
		}
